import React, { useState, useRef, useCallback } from 'react';
import styled from 'styled-components';
import { Camera, X, RotateCcw, Check } from 'lucide-react';

const CameraContainer = styled.div`
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: black;
  z-index: 1000;
  display: flex;
  flex-direction: column;
`;

const CameraHeader = styled.div`
  position: absolute;
  top: 20px;
  left: 20px;
  right: 20px;
  z-index: 1001;
  display: flex;
  justify-content: space-between;
  align-items: center;
`;

const CloseButton = styled.button`
  background: rgba(0, 0, 0, 0.5);
  color: white;
  border: none;
  border-radius: 50%;
  width: 50px;
  height: 50px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.3s ease;

  &:hover {
    background: rgba(0, 0, 0, 0.7);
  }
`;

const CameraTitle = styled.h2`
  color: white;
  font-size: 18px;
  font-weight: 600;
`;

const CameraView = styled.div`
  flex: 1;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
`;

const Video = styled.video`
  width: 100%;
  height: 100%;
  object-fit: cover;
`;

const Canvas = styled.canvas`
  display: none;
`;

const CameraControls = styled.div`
  position: absolute;
  bottom: 30px;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  gap: 20px;
  align-items: center;
`;

const CaptureButton = styled.button`
  width: 80px;
  height: 80px;
  border-radius: 50%;
  border: 4px solid white;
  background: rgba(255, 255, 255, 0.3);
  cursor: pointer;
  transition: all 0.3s ease;
  display: flex;
  align-items: center;
  justify-content: center;

  &:hover {
    background: rgba(255, 255, 255, 0.5);
    transform: scale(1.1);
  }

  &:active {
    transform: scale(0.95);
  }
`;

const ControlButton = styled.button`
  width: 50px;
  height: 50px;
  border-radius: 50%;
  background: rgba(0, 0, 0, 0.5);
  color: white;
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.3s ease;

  &:hover {
    background: rgba(0, 0, 0, 0.7);
  }
`;

const PreviewContainer = styled.div`
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: black;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
`;

const PreviewImage = styled.img`
  max-width: 90%;
  max-height: 80%;
  border-radius: 12px;
`;

const PreviewControls = styled.div`
  position: absolute;
  bottom: 30px;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  gap: 20px;
`;

const ActionButton = styled.button`
  padding: 12px 24px;
  border-radius: 25px;
  border: none;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  display: flex;
  align-items: center;
  gap: 8px;

  &.retake {
    background: #6c757d;
    color: white;

    &:hover {
      background: #5a6268;
    }
  }

  &.use {
    background: #28a745;
    color: white;

    &:hover {
      background: #218838;
    }
  }
`;

const ErrorMessage = styled.div`
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  background: rgba(220, 53, 69, 0.9);
  color: white;
  padding: 20px;
  border-radius: 12px;
  text-align: center;
  max-width: 300px;
`;

const CameraCapture = ({ onCapture, onClose }) => {
  const [stream, setStream] = useState(null);
  const [isCaptured, setIsCaptured] = useState(false);
  const [capturedImage, setCapturedImage] = useState(null);
  const [error, setError] = useState(null);
  const [facingMode, setFacingMode] = useState('environment'); // 'user' or 'environment'

  const videoRef = useRef(null);
  const canvasRef = useRef(null);

  const startCamera = useCallback(async () => {
    try {
      setError(null);

      // Kiểm tra hỗ trợ camera
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error('Camera không được hỗ trợ trên thiết bị này');
      }

      // Yêu cầu quyền truy cập camera
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: {
          facingMode: facingMode,
          width: { ideal: 1280 },
          height: { ideal: 720 }
        }
      });

      setStream(mediaStream);

      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (err) {
      console.error('Lỗi khi khởi động camera:', err);
      setError(err.message);
    }
  }, [facingMode]);

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  }, [stream]);

  const capturePhoto = useCallback(() => {
    if (!videoRef.current || !canvasRef.current) return;

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const context = canvas.getContext('2d');

    // Set canvas size to video size
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;

    // Draw video frame to canvas
    context.drawImage(video, 0, 0, canvas.width, canvas.height);

    // Convert to blob
    canvas.toBlob((blob) => {
      if (blob) {
        const imageUrl = URL.createObjectURL(blob);
        setCapturedImage(imageUrl);
        setIsCaptured(true);
        stopCamera();
      }
    }, 'image/jpeg', 0.9);
  }, [stopCamera]);

  const retakePhoto = useCallback(() => {
    setIsCaptured(false);
    setCapturedImage(null);
    startCamera();
  }, [startCamera]);

  const usePhoto = useCallback(() => {
    if (capturedImage) {
      // Convert blob URL to file
      fetch(capturedImage)
        .then(res => res.blob())
        .then(blob => {
          const file = new File([blob], 'camera-capture.jpg', { type: 'image/jpeg' });
          onCapture(capturedImage, file);
          onClose();
        });
    }
  }, [capturedImage, onCapture, onClose]);

  const switchCamera = useCallback(() => {
    setFacingMode(prev => prev === 'user' ? 'environment' : 'user');
  }, []);

  // Start camera when component mounts
  React.useEffect(() => {
    startCamera();

    return () => {
      stopCamera();
    };
  }, [startCamera, stopCamera]);

  // Restart camera when facing mode changes
  React.useEffect(() => {
    if (stream) {
      stopCamera();
      startCamera();
    }
  }, [facingMode, startCamera, stopCamera]);

  if (error) {
    return (
      <CameraContainer>
        <CameraHeader>
          <CloseButton onClick={onClose}>
            <X size={24} />
          </CloseButton>
          <CameraTitle>Camera</CameraTitle>
        </CameraHeader>
        <ErrorMessage>
          <h3>Không thể truy cập camera</h3>
          <p>{error}</p>
          <button onClick={startCamera} style={{ marginTop: '10px', padding: '8px 16px' }}>
            Thử lại
          </button>
        </ErrorMessage>
      </CameraContainer>
    );
  }

  if (isCaptured && capturedImage) {
    return (
      <CameraContainer>
        <PreviewContainer>
          <PreviewImage src={capturedImage} alt="Captured" />
          <PreviewControls>
            <ActionButton className="retake" onClick={retakePhoto}>
              <RotateCcw size={20} />
              Chụp lại
            </ActionButton>
            <ActionButton className="use" onClick={usePhoto}>
              <Check size={20} />
              Sử dụng
            </ActionButton>
          </PreviewControls>
        </PreviewContainer>
      </CameraContainer>
    );
  }

  return (
    <CameraContainer>
      <CameraHeader>
        <CloseButton onClick={onClose}>
          <X size={24} />
        </CloseButton>
        <CameraTitle>Chụp ảnh côn trùng</CameraTitle>
        <ControlButton onClick={switchCamera}>
          <RotateCcw size={20} />
        </ControlButton>
      </CameraHeader>

      <CameraView>
        <Video
          ref={videoRef}
          autoPlay
          playsInline
          muted
        />
        <Canvas ref={canvasRef} />
      </CameraView>

      <CameraControls>
        <CaptureButton onClick={capturePhoto} />
      </CameraControls>
    </CameraContainer>
  );
};

export default CameraCapture;
